  XCircle
} from 'lucide-react';
import EmojiScale from '../components/EmojiScale';

const SurveyResponse = () => {
  const { id } = useParams();
  const [survey, setSurvey] = useState(null);
  const [responses, setResponses] = useState({});
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [sessionId] = useState(`session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`);

  useEffect(() => {
    fetchSurvey();
  }, [id]);

  const fetchSurvey = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`/api/surveys/public/${id}`);
      setSurvey(response.data);

      // Initialize responses object
      const initialResponses = {};
      response.data.questions.forEach(question => {
        initialResponses[question.id] = null;
      });
      setResponses(initialResponses);
    } catch (error) {
      console.error('Error fetching survey:', error);
      toast.error('Survey not found or not available');
    } finally {
      setLoading(false);
    }
  };

  const handleResponse = (questionId, answer) => {
    setResponses(prev => ({
      ...prev,
      [questionId]: answer
    }));
  };

  const nextQuestion = () => {
    if (currentQuestionIndex < survey.questions.length - 1) {
      setCurrentQuestionIndex(currentQuestionIndex + 1);
    }
  };

  const previousQuestion = () => {
    if (currentQuestionIndex > 0) {
      setCurrentQuestionIndex(currentQuestionIndex - 1);
    }
  };

  const submitSurvey = async () => {
    try {
      setSubmitting(true);

      const surveyResponses = Object.entries(responses)
        .filter(([_, answer]) => answer !== null)
        .map(([questionId, answer]) => ({
          questionId: parseInt(questionId),
          answer
        }));

      await axios.post('/api/responses', {
        surveyId: parseInt(id),
        responses: surveyResponses,
        sessionId
      });

      toast.success('Thank you for your responses!');
      // Redirect to a thank you page or show completion message
      setTimeout(() => {
        window.close();
      }, 2000);
    } catch (error) {
      console.error('Error submitting responses:', error);
      toast.error('Failed to submit responses');
    } finally {
      setSubmitting(false);
    }
  };

  const renderQuestion = (question) => {
    const progress = ((currentQuestionIndex + 1) / survey.questions.length) * 100;

    return (
      <div className="max-w-2xl mx-auto">
        {/* Progress Bar */}
        <div className="mb-8">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm text-gray-600">
              Question {currentQuestionIndex + 1} of {survey.questions.length}
            </span>
            <span className="text-sm font-medium text-gray-900">
              {Math.round(progress)}% Complete
            </span>
          </div>
          <div className="w-full bg-gray-200 rounded-full h-2">
            <div
              className="bg-primary-600 h-2 rounded-full transition-all duration-300"
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>

        {/* Question */}
        <div className="card p-8">
          <div className="mb-6">
            <h2 className="text-2xl font-bold text-gray-900 mb-2">
              {question.title}
            </h2>
            {question.description && (
              <p className="text-gray-600">{question.description}</p>
            )}
            {question.required && (
              <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800 mt-2">
                Required
              </span>
            )}
          </div>

          {/* Question Content */}
          <div className="mb-8">
            {renderQuestionContent(question)}
          </div>

          {/* Navigation */}
          <div className="flex items-center justify-between">
            <button
              onClick={previousQuestion}
              disabled={currentQuestionIndex === 0}
              className="btn-secondary disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              Previous
            </button>

            <div className="flex items-center space-x-2">
              {currentQuestionIndex === survey.questions.length - 1 ? (
                <button
                  onClick={submitSurvey}
                  disabled={submitting}
                  className="btn-primary"
                >
                  {submitting ? (
                    <div className="spinner w-4 h-4 mr-2"></div>
                  ) : (
                    <Send className="h-4 w-4 mr-2" />
                  )}
                  Submit Survey
                </button>
              ) : (
                <button
                  onClick={nextQuestion}
                  className="btn-primary"
                >
                  Next
                  <ArrowRight className="h-4 w-4 ml-2" />
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  };

  const renderQuestionContent = (question) => {
    const currentResponse = responses[question.id];

    switch (question.type) {
      case 'emoji_scale':
        return (
          <div className="space-y-4">
            <EmojiScale
              options={question.options}
              value={currentResponse}
              onChange={(value) => handleResponse(question.id, value)}
            />
            {currentResponse && (
              <div className="text-center p-4 bg-primary-50 rounded-lg">
                <p className="text-primary-700 font-medium">
                  You selected: {question.options.find(opt => opt.value === currentResponse)?.label}
                </p>
              </div>
            )}
          </div>
        );

      case 'multiple_choice':
        return (
          <div className="space-y-3">
            {question.options.map((option, index) => (
              <label
                key={index}
                className="flex items-center p-4 border border-gray-200 rounded-lg cursor-pointer hover:border-primary-300 hover:bg-primary-50 transition-colors"
              >
                <input
                  type="radio"
                  name={`question-${question.id}`}
                  value={typeof option === 'object' ? option.value || option.label : option}
                  checked={currentResponse === (typeof option === 'object' ? option.value || option.label : option)}
                  onChange={(e) => handleResponse(question.id, e.target.value)}
                  className="sr-only"
                />
                <div className="flex items-center">
                  {currentResponse === (typeof option === 'object' ? option.value || option.label : option) ? (
                    <CheckCircle className="h-5 w-5 text-primary-600 mr-3" />
                  ) : (
                    <Circle className="h-5 w-5 text-gray-400 mr-3" />
                  )}
                  <span className="text-gray-900">{typeof option === 'object' ? option.label || option.value : option}</span>
                </div>
              </label>
            ))}
          </div>
        );

      case 'text':
        return (
          <div>
            <textarea
              value={currentResponse || ''}
              onChange={(e) => handleResponse(question.id, e.target.value)}
              className="w-full p-4 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 resize-none"
              rows="4"
              placeholder="Enter your answer here..."
            />
          </div>
        );

      case 'likert_scale':
        const scaleOptions = [];
        const min = question.settings?.min || 1;
        const max = question.settings?.max || 10;

        for (let i = min; i <= max; i++) {
          scaleOptions.push({
            value: i,
            label: i.toString(),
            emoji: i <= (max - min) / 2 ? '😞' : i === Math.ceil((max - min) / 2) ? '😐' : '😊'
          });
        }

        return (
          <div className="space-y-4">
            <EmojiScale
              options={scaleOptions}
              value={currentResponse}
              onChange={(value) => handleResponse(question.id, value)}
            />
            {currentResponse && (
              <div className="text-center p-4 bg-primary-50 rounded-lg">
                <p className="text-primary-700 font-medium">
                  You rated: {currentResponse}/10
                </p>
              </div>
            )}
          </div>
        );

      case 'phone':
        return (
          <div className="space-y-3">
            <div className="flex items-center space-x-2">
              <select 
                className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                defaultValue="+233"
              >
                <option value="+233">🇬🇭 +233</option>
                <option value="+1">🇺🇸 +1</option>
                <option value="+44">🇬🇧 +44</option>
                <option value="+91">🇮🇳 +91</option>
                <option value="+86">🇨🇳 +86</option>
              </select>
              <input
                type="tel"
                value={currentResponse || ''}
                onChange={(e) => handleResponse(question.id, e.target.value)}
                className="flex-1 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                placeholder="Enter phone number"
              />
            </div>
          </div>
        );

      default:
        return (
          <div className="text-center py-8">
            <p className="text-gray-500">Question type not supported</p>
          </div>
        );
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="spinner w-8 h-8 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading survey...</p>
        </div>
      </div>
    );
  }

  if (!survey) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <XCircle className="h-8 w-8 text-red-600" />
          </div>
          <h2 className="text-xl font-bold text-gray-900 mb-2">Survey Not Found</h2>
          <p className="text-gray-600">This survey is not available or has been removed.</p>
        </div>
      </div>
    );
  }

  const currentQuestion = survey.questions[currentQuestionIndex];

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white shadow-sm border-b">
        <div className="max-w-4xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-xl font-bold text-gray-900">{survey.title}</h1>
              {survey.description && (
                <p className="text-gray-600 text-sm mt-1">{survey.description}</p>
              )}
            </div>
            <div className="flex items-center space-x-2">
              <Smile className="h-5 w-5 text-primary-600" />
              <span className="text-sm text-gray-600">SurveyGuy</span>
            </div>
          </div>
        </div>
      </div>

      {/* Survey Content */}
      <div className="max-w-4xl mx-auto px-4 py-8">
        {renderQuestion(currentQuestion)}
      </div>

      {/* Footer */}
      <div className="bg-white border-t mt-12">
        <div className="max-w-4xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between text-sm text-gray-500">
            <span>Powered by SurveyGuy</span>
            <span>Your responses are anonymous</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SurveyResponse;
